   2→import { useCallback, useEffect, useMemo, useRef, useState } from "react";
   3→import { Group, Image as KonvaImage, Layer, Line, Rect, Stage, Text } from "react-konva";
   4→import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
   5→import {
   6→    createFreedomWallItem,
   7→    deleteFreedomWallItem,
   8→    getCurrentFreedomWallWeek,
   9→    getFreedomWallItems,
  10→    getFreedomWallStickers,
  11→    updateFreedomWallItem
  12→} from "../../../../API/Api";
  13→import { useAuth } from "../../../Context/useAuth";
  14→import supabase from "../../../utils/supabaseClient";
  15→import "./freedomWall.css";
  16→
  17→const STAMP_ICONS = {
  18→    heart: "❤️",
  19→    star: "⭐",
  20→    fire: "🔥",
  21→    sparkles: "✨",
  22→    wow: "💥"
  23→};
  24→
  25→const NOTE_FONT_OPTIONS = [
  26→    "Arial",
  27→    "Georgia",
  28→    "Courier New",
  29→    "Trebuchet MS",
  30→    "Times New Roman"
  31→];
  32→
  33→const NOTE_STYLE_OPTIONS = ["normal", "bold", "italic"];
  34→const WALL_MAX_WIDTH = 1080;
  35→const WALL_MIN_HEIGHT = 420;
  36→const WALL_MAX_HEIGHT = 900;
  37→
  38→const clamp = (value, min, max) => Math.min(Math.max(value, min), max);
  39→
  40→const sortItemsByZIndex = (items = []) => [...items].sort((a, b) => {
  41→    const zDiff = (a?.z_index || 0) - (b?.z_index || 0);
  42→    if(zDiff !== 0){
  43→        return zDiff;
  44→    }
  45→
  46→    const dateDiff = new Date(a?.created_at || 0) - new Date(b?.created_at || 0);
  47→    if(dateDiff !== 0){
  48→        return dateDiff;
  49→    }
  50→
  51→    return String(a?.id || "").localeCompare(String(b?.id || ""));
  52→});
  53→
  54→const upsertById = (items = [], nextItem) => {
  55→    const existingIndex = items.findIndex((item) => String(item?.id) === String(nextItem?.id));
  56→    if(existingIndex === -1){
  57→        return [...items, nextItem];
  58→    }
  59→
  60→    const nextItems = [...items];
  61→    const previousItem = nextItems[existingIndex];
  62→    nextItems[existingIndex] = {
  63→        ...previousItem,
  64→        ...nextItem,
  65→        payload: {
  66→            ...(previousItem?.payload || {}),
  67→            ...(nextItem?.payload || {})
  68→        },
  69→        users: nextItem?.users || previousItem?.users || null
  70→    };
  71→    return nextItems;
  72→};
  73→
  74→const removeById = (items = [], itemId) => items.filter((item) => String(item?.id) !== String(itemId));
  75→
  76→const useLoadedImage = (src) => {
  77→    const [image, setImage] = useState(null);
  78→
  79→    useEffect(() => {
  80→        if(!src){
  81→            setImage(null);
  82→            return;
  83→        }
  84→
  85→        const img = new window.Image();
  86→        img.crossOrigin = "anonymous";
  87→        img.onload = () => setImage(img);
  88→        img.onerror = () => setImage(null);
  89→        img.src = src;
  90→
  91→        return () => {
  92→            img.onload = null;
  93→            img.onerror = null;
  94→        };
  95→    }, [src]);
  96→
  97→    return image;
  98→};
  99→
 100→const StickerNode = ({item, assetUrl, stageWidth, stageHeight, isSelected, canEdit, onSelect, onDragEnd}) => {
 101→    const image = useLoadedImage(assetUrl);
 102→    const scale = clamp(Number(item?.payload?.scale) || 1, 0.25, 6);
 103→    const size = clamp(88 * scale, 20, 420);
 104→    const x = clamp((Number(item?.payload?.x) || 0.5) * stageWidth, 0, Math.max(0, stageWidth - size));
 105→    const y = clamp((Number(item?.payload?.y) || 0.5) * stageHeight, 0, Math.max(0, stageHeight - size));
 106→
 107→    if(!image){
 108→        return null;
 109→    }
 110→
 111→    return (
 112→        <>
 113→            <KonvaImage
 114→                x={x}
 115→                y={y}
 116→                width={size}
 117→                height={size}
 118→                image={image}
 119→                rotation={Number(item?.payload?.rotation) || 0}
 120→                draggable={canEdit}
 121→                onClick={onSelect}
 122→                onTap={onSelect}
 123→                onDragEnd={onDragEnd}
 124→            />
 125→            {isSelected && (
 126→                <Rect
 127→                    x={x}
 128→                    y={y}
 129→                    width={size}
 130→                    height={size}
 131→                    stroke="#4f46e5"
 132→                    strokeWidth={2}
 133→                    dash={[6, 4]}
 134→                    listening={false}
 135→                />
 136→            )}
 137→        </>
 138→    );
 139→};
 140→
 141→const StampNode = ({item, stageWidth, stageHeight, canEdit, onSelect, onDragEnd, isSelected}) => {
 142→    const stamp = STAMP_ICONS[item?.payload?.stamp] || "✨";
 143→    const scale = clamp(Number(item?.payload?.scale) || 1, 0.35, 5);
 144→    const size = clamp(34 * scale, 14, 220);
 145→    const x = clamp((Number(item?.payload?.x) || 0.5) * stageWidth, 0, Math.max(0, stageWidth - size));
 146→    const y = clamp((Number(item?.payload?.y) || 0.5) * stageHeight, 0, Math.max(0, stageHeight - size));
 147→
 148→    return (
 149→        <>
 150→            <Text
 151→                x={x}
 152→                y={y}
 153→                width={size}
 154→                height={size}
 155→                text={stamp}
 156→                fontSize={size * 0.9}
 157→                align="center"
 158→                verticalAlign="middle"
 159→                draggable={canEdit}
 160→                onClick={onSelect}
 161→                onTap={onSelect}
 162→                onDragEnd={onDragEnd}
 163→                rotation={Number(item?.payload?.rotation) || 0}
 164→            />
 165→            {isSelected && (
 166→                <Rect
 167→                    x={x}
 168→                    y={y}
 169→                    width={size}
 170→                    height={size}
 171→                    stroke="#0f766e"
 172→                    strokeWidth={2}
 173→                    dash={[6, 4]}
 174→                    listening={false}
 175→                />
 176→            )}
 177→        </>
 178→    );
 179→};
 180→
 181→const NoteNode = ({item, stageWidth, stageHeight, canEdit, onSelect, onDragEnd, isSelected}) => {
 182→    const payload = item?.payload || {};
 183→    const width = clamp((Number(payload?.width) || 0.26) * stageWidth, 110, stageWidth * 0.9);
 184→    const height = clamp((Number(payload?.height) || 0.2) * stageHeight, 60, stageHeight * 0.8);
 185→    const x = clamp((Number(payload?.x) || 0.45) * stageWidth, 0, Math.max(0, stageWidth - width));
 186→    const y = clamp((Number(payload?.y) || 0.45) * stageHeight, 0, Math.max(0, stageHeight - height));
 187→    const fontStyle = NOTE_STYLE_OPTIONS.includes(payload?.fontStyle) ? payload.fontStyle : "normal";
 188→
 189→    return (
 190→        <Group
 191→            x={x}
 192→            y={y}
 193→            draggable={canEdit}
 194→            onDragEnd={onDragEnd}
 195→            onClick={onSelect}
 196→            onTap={onSelect}
 197→            rotation={Number(payload?.rotation) || 0}
 198→        >
 199→            <Rect
 200→                width={width}
 201→                height={height}
 202→                cornerRadius={12}
 203→                fill={payload?.bgColor || "#fff4a8"}
 204→                shadowColor="rgba(0,0,0,0.2)"
 205→                shadowBlur={8}
 206→                shadowOffsetY={3}
 207→                stroke={isSelected ? "#a21caf" : "rgba(0,0,0,0.08)"}
 208→                strokeWidth={isSelected ? 2 : 1}
 209→            />
 210→            <Text
 211→                x={10}
 212→                y={10}
 213→                width={width - 20}
 214→                height={height - 20}
 215→                text={payload?.text || ""}
 216→                fontFamily={payload?.fontFamily || "Arial"}
 217→                fontStyle={fontStyle}
 218→                fontSize={clamp(Number(payload?.fontSize) || 16, 10, 64)}
 219→                fill={payload?.fontColor || "#1f2937"}
 220→                wrap="word"
 221→                lineHeight={1.2}
 222→            />
 223→        </Group>
 224→    );
 225→};
 226→
 227→const formatWeekLabel = (week = null) => {
 228→    if(!week?.week_start || !week?.week_end){
 229→        return "No active week";
 230→    }
 231→
 232→    const startDate = new Date(week.week_start);
 233→    const endDate = new Date(week.week_end);
 234→    return `${startDate.toLocaleDateString()} - ${endDate.toLocaleDateString()} (UTC)`;
 235→};
 236→
 237→const isCanvasBackgroundTarget = (target, stage) => {
 238→    if(!target || !stage){
 239→        return false;
 240→    }
 241→
 242→    if(target === stage){
 243→        return true;
 244→    }
 245→
 246→    return target.getParent?.() === stage;
 247→};
