 249→const FreedomWallPage = () => {
 250→    const {session, user, openAuthModal} = useAuth();
 251→    const queryClient = useQueryClient();
 252→    const shellRef = useRef(null);
 253→    const draftDoodleRef = useRef([]);
 254→    const [shellWidth, setShellWidth] = useState(980);
 255→    const [activeTool, setActiveTool] = useState("doodle");
 256→    const [doodleColor, setDoodleColor] = useState("#5f92ff");
 257→    const [doodleSize, setDoodleSize] = useState(3.2);
 258→    const [draftDoodlePoints, setDraftDoodlePoints] = useState([]);
 259→    const [isDrawing, setIsDrawing] = useState(false);
 260→    const [selectedStickerId, setSelectedStickerId] = useState("");
 261→    const [selectedStamp, setSelectedStamp] = useState("heart");
 262→    const [noteDraftText, setNoteDraftText] = useState("New note");
 263→    const [selectedItemId, setSelectedItemId] = useState(null);
 264→    const [noteEditor, setNoteEditor] = useState({
 265→        text: "",
 266→        fontFamily: "Arial",
 267→        fontStyle: "normal",
 268→        fontColor: "#1f2937",
 269→        bgColor: "#fff4a8",
 270→        fontSize: 16
 271→    });
 272→
 273→    const authToken = session?.access_token || null;
 274→    const currentUser = user?.userData?.[0] || null;
 275→    const currentUserId = currentUser?.id || null;
 276→    const canWrite = Boolean(currentUserId);
 277→
 278→    const {
 279→        data: activeWeekData,
 280→        isLoading: isWeekLoading,
 281→        error: weekError
 282→    } = useQuery({
 283→        queryKey: ["freedomWallCurrentWeek"],
 284→        queryFn: () => getCurrentFreedomWallWeek(authToken),
 285→        refetchOnWindowFocus: true,
 286→        staleTime: 30 * 1000
 287→    });
 288→
 289→    const activeWeek = activeWeekData?.week || null;
 290→    const weekId = activeWeek?.id || null;
 291→
 292→    const itemsQueryKey = useMemo(() => ["freedomWallItems", weekId], [weekId]);
 293→
 294→    const {data: stickerData} = useQuery({
 295→        queryKey: ["freedomWallStickers"],
 296→        queryFn: () => getFreedomWallStickers(authToken),
 297→        refetchOnWindowFocus: false,
 298→        staleTime: 60 * 1000
 299→    });
 300→
 301→    const {
 302→        data: itemsData,
 303→        isLoading: isItemsLoading
 304→    } = useQuery({
 305→        queryKey: itemsQueryKey,
 306→        queryFn: () => getFreedomWallItems(weekId, {limit: 400}, authToken),
 307→        enabled: Boolean(weekId),
 308→        refetchOnWindowFocus: false,
 309→        staleTime: 20 * 1000
 310→    });
 311→
 312→    const stickers = stickerData?.stickers || [];
 313→    const stickerAssetMap = useMemo(() => {
 314→        return new Map(stickers.map((sticker) => [String(sticker.id), sticker.asset_url]));
 315→    }, [stickers]);
 316→
 317→    useEffect(() => {
 318→        if(!selectedStickerId && stickers.length > 0){
 319→            setSelectedStickerId(String(stickers[0].id));
 320→        }
 321→    }, [selectedStickerId, stickers]);
 322→
 323→    useEffect(() => {
 324→        const updateShellWidth = () => {
 325→            const nextWidth = shellRef.current?.clientWidth || 980;
 326→            setShellWidth(nextWidth);
 327→        };
 328→
 329→        updateShellWidth();
 330→        window.addEventListener("resize", updateShellWidth);
 331→
 332→        let resizeObserver = null;
 333→        if(typeof ResizeObserver !== "undefined" && shellRef.current){
 334→            resizeObserver = new ResizeObserver(updateShellWidth);
 335→            resizeObserver.observe(shellRef.current);
 336→        }
 337→
 338→        return () => {
 339→            window.removeEventListener("resize", updateShellWidth);
 340→            if(resizeObserver){
 341→                resizeObserver.disconnect();
 342→            }
 343→        };
 344→    }, []);
 345→
 346→    const stageWidth = useMemo(() => clamp(shellWidth - 12, 280, WALL_MAX_WIDTH), [shellWidth]);
 347→    const stageHeight = useMemo(() => clamp(Math.round(stageWidth * 0.64), WALL_MIN_HEIGHT, WALL_MAX_HEIGHT), [stageWidth]);
 348→
 349→    const sortedItems = useMemo(() => sortItemsByZIndex(itemsData?.data || []), [itemsData?.data]);
 350→    const maxZIndex = useMemo(() => {
 351→        if(!sortedItems.length){
 352→            return 0;
 353→        }
 354→        return sortedItems.reduce((maxValue, item) => Math.max(maxValue, Number(item?.z_index) || 0), 0);
 355→    }, [sortedItems]);
 356→
 357→    const selectedItem = useMemo(() => {
 358→        if(!selectedItemId){
 359→            return null;
 360→        }
 361→        return sortedItems.find((item) => String(item?.id) === String(selectedItemId)) || null;
 362→    }, [selectedItemId, sortedItems]);
 363→
 364→    const selectedNote = useMemo(() => (
 365→        selectedItem?.item_type === "note" ? selectedItem : null
 366→    ), [selectedItem]);
 367→
 368→    const selectedItemCanEdit = Boolean(selectedItem && currentUserId && String(selectedItem.user_id) === String(currentUserId));
 369→
 370→    useEffect(() => {
 371→        if(!selectedNote){
 372→            return;
 373→        }
 374→
 375→        const payload = selectedNote.payload || {};
 376→        setNoteEditor({
 377→            text: payload.text || "",
 378→            fontFamily: payload.fontFamily || "Arial",
 379→            fontStyle: NOTE_STYLE_OPTIONS.includes(payload.fontStyle) ? payload.fontStyle : "normal",
 380→            fontColor: payload.fontColor || "#1f2937",
 381→            bgColor: payload.bgColor || "#fff4a8",
 382→            fontSize: clamp(Number(payload.fontSize) || 16, 10, 64)
 383→        });
 384→    }, [selectedNote]);
 385→
 386→    const setItemsCache = useCallback((updater) => {
 387→        if(!weekId){
 388→            return;
 389→        }
 390→
 391→        queryClient.setQueryData(itemsQueryKey, (old) => {
 392→            const previousItems = Array.isArray(old?.data) ? old.data : [];
 393→            const nextItems = sortItemsByZIndex(updater(previousItems));
 394→            return {
 395→                ...(old || {}),
 396→                data: nextItems,
 397→                hasMore: false,
 398→                nextCursor: null
 399→            };
 400→        });
 401→    }, [itemsQueryKey, queryClient, weekId]);
 402→
 403→    const createItemMutation = useMutation({
 404→        mutationFn: ({payload}) => createFreedomWallItem(authToken, payload),
 405→        onMutate: async({payload}) => {
 406→            const optimisticId = `optimistic-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
 407→            const optimisticItem = {
 408→                id: optimisticId,
 409→                week_id: payload.weekId,
 410→                user_id: currentUserId,
 411→                item_type: payload.itemType,
 412→                payload: payload.payload,
 413→                z_index: payload.zIndex || 0,
 414→                created_at: new Date().toISOString(),
 415→                updated_at: new Date().toISOString(),
 416→                deleted_at: null,
 417→                users: currentUser ? {
 418→                    id: currentUser.id,
 419→                    name: currentUser.name,
 420→                    image_url: currentUser.image_url,
 421→                    badge: currentUser.badge
 422→                } : null
 423→            };
 424→
 425→            setItemsCache((items) => [...items, optimisticItem]);
 426→            return {optimisticId: optimisticId};
 427→        },
 428→        onSuccess: (response, _variables, context) => {
 429→            const createdItem = response?.item;
 430→            if(!createdItem?.id){
 431→                return;
 432→            }
 433→
 434→            setItemsCache((items) => {
 435→                const withoutOptimistic = context?.optimisticId
 436→                    ? removeById(items, context.optimisticId)
 437→                    : items;
 438→                return upsertById(withoutOptimistic, createdItem);
 439→            });
 440→        },
 441→        onError: (_error, _variables, context) => {
 442→            if(!context?.optimisticId){
 443→                return;
 444→            }
 445→            setItemsCache((items) => removeById(items, context.optimisticId));
 446→        }
 447→    });
 448→
 449→    const updateItemMutation = useMutation({
 450→        mutationFn: ({itemId, payload}) => updateFreedomWallItem(authToken, itemId, payload),
 451→        onMutate: async({itemId, payload}) => {
 452→            let previousItem = null;
 453→            setItemsCache((items) => {
 454→                previousItem = items.find((item) => String(item?.id) === String(itemId)) || null;
 455→                if(!previousItem){
 456→                    return items;
 457→                }
 458→
 459→                return items.map((item) => {
 460→                    if(String(item?.id) !== String(itemId)){
 461→                        return item;
 462→                    }
 463→
 464→                    const mergedPayload = payload?.payload !== undefined
 465→                        ? {...(item?.payload || {}), ...(payload.payload || {})}
 466→                        : item?.payload;
 467→
 468→                    return {
 469→                        ...item,
 470→                        payload: mergedPayload,
 471→                        z_index: payload?.zIndex !== undefined ? payload.zIndex : item?.z_index
 472→                    };
 473→                });
 474→            });
 475→            return {previousItem: previousItem};
 476→        },
 477→        onSuccess: (response) => {
 478→            const updatedItem = response?.item;
 479→            if(!updatedItem?.id){
 480→                return;
 481→            }
 482→
 483→            setItemsCache((items) => upsertById(items, updatedItem));
 484→        },
 485→        onError: (_error, variables, context) => {
 486→            if(!context?.previousItem){
 487→                return;
 488→            }
 489→
 490→            setItemsCache((items) => upsertById(items, context.previousItem));
 491→            if(variables?.itemId){
 492→                setSelectedItemId(String(variables.itemId));
 493→            }
 494→        }
 495→    });
 496→
 497→    const deleteItemMutation = useMutation({
 498→        mutationFn: ({itemId}) => deleteFreedomWallItem(authToken, itemId),
 499→        onMutate: async({itemId}) => {
 500→            let removedItem = null;
 501→            setItemsCache((items) => {
 502→                removedItem = items.find((item) => String(item?.id) === String(itemId)) || null;
 503→                return removeById(items, itemId);
 504→            });
 505→            return {removedItem: removedItem};
 506→        },
 507→        onError: (_error, _variables, context) => {
 508→            if(!context?.removedItem){
 509→                return;
 510→            }
 511→            setItemsCache((items) => upsertById(items, context.removedItem));
 512→        }
 513→    });
 514→
 515→    useEffect(() => {
 516→        if(!weekId){
 517→            return;
 518→        }
 519→
 520→        const channel = supabase
 521→            .channel(`freedom-wall-${weekId}`)
 522→            .on(
 523→                "postgres_changes",
 524→                {event: "*", schema: "public", table: "freedom_wall_items", filter: `week_id=eq.${weekId}`},
 525→                (payload) => {
 526→                    const eventType = payload?.eventType;
 527→                    const oldRow = payload?.old || null;
 528→                    const newRow = payload?.new || null;
 529→
 530→                    if(eventType === "DELETE" && oldRow?.id){
 531→                        setItemsCache((items) => removeById(items, oldRow.id));
 532→                        return;
 533→                    }
 534→
 535→                    if(!newRow?.id){
 536→                        return;
 537→                    }
 538→
 539→                    if(newRow?.deleted_at){
 540→                        setItemsCache((items) => removeById(items, newRow.id));
 541→                        return;
 542→                    }
 543→
 544→                    setItemsCache((items) => {
 545→                        const previous = items.find((item) => String(item?.id) === String(newRow.id)) || null;
 546→                        const fallbackUsers = previous?.users || (currentUserId && String(newRow.user_id) === String(currentUserId)
 547→                            ? {
 548→                                id: currentUser?.id,
 549→                                name: currentUser?.name,
 550→                                image_url: currentUser?.image_url,
 551→                                badge: currentUser?.badge
 552→                            }
 553→                            : null);
 554→                        const normalized = {
 555→                            ...newRow,
 556→                            users: fallbackUsers
 557→                        };
 558→
 559→                        return upsertById(items, normalized);
 560→                    });
 561→                }
 562→            )
 563→            .subscribe();
 564→
 565→        return () => {
 566→            supabase.removeChannel(channel);
 567→        };
 568→    }, [currentUser?.badge, currentUser?.id, currentUser?.image_url, currentUser?.name, currentUserId, setItemsCache, weekId]);
 569→
 570→    const ensureCanWrite = useCallback(() => {
 571→        if(canWrite){
 572→            return true;
 573→        }
 574→        openAuthModal?.();
 575→        return false;
 576→    }, [canWrite, openAuthModal]);
 577→
 578→    const getNormalizedPointerPosition = (stage) => {
 579→        const pointer = stage?.getPointerPosition();
 580→        if(!pointer){
 581→            return null;
 582→        }
 583→        return {
 584→            x: clamp(pointer.x / stageWidth, 0, 1),
 585→            y: clamp(pointer.y / stageHeight, 0, 1)
 586→        };
 587→    };
 588→
 589→    const createWallItem = useCallback((itemType, payload) => {
 590→        if(!weekId || !ensureCanWrite()){
 591→            return;
 592→        }
 593→
 594→        createItemMutation.mutate({
 595→            payload: {
 596→                weekId: weekId,
 597→                itemType: itemType,
 598→                payload: payload,
 599→                zIndex: maxZIndex + 1
 600→            }
 601→        });
 602→    }, [createItemMutation, ensureCanWrite, maxZIndex, weekId]);
 603→
 604→    const handlePlaceItem = useCallback((stage) => {
 605→        const pointer = getNormalizedPointerPosition(stage);
 606→        if(!pointer){
 607→            return;
 608→        }
 609→
 610→        if(activeTool === "sticker"){
 611→            if(!selectedStickerId){
 612→                return;
 613→            }
 614→
 615→            createWallItem("sticker", {
 616→                stickerId: selectedStickerId,
 617→                x: pointer.x,
 618→                y: pointer.y,
 619→                scale: 1,
 620→                rotation: 0
 621→            });
 622→            return;
 623→        }
 624→
 625→        if(activeTool === "stamp"){
 626→            createWallItem("stamp", {
 627→                stamp: selectedStamp,
 628→                x: pointer.x,
 629→                y: pointer.y,
 630→                scale: 1,
 631→                rotation: 0
 632→            });
 633→            return;
 634→        }
 635→
 636→        if(activeTool === "note"){
 637→            const noteText = noteDraftText.trim();
 638→            if(!noteText){
 639→                return;
 640→            }
 641→
 642→            createWallItem("note", {
 643→                text: noteText,
 644→                x: pointer.x,
 645→                y: pointer.y,
 646→                width: 0.26,
 647→                height: 0.2,
 648→                rotation: 0,
 649→                fontFamily: noteEditor.fontFamily || "Arial",
 650→                fontStyle: noteEditor.fontStyle || "normal",
 651→                fontColor: noteEditor.fontColor || "#1f2937",
 652→                bgColor: noteEditor.bgColor || "#fff4a8",
 653→                fontSize: clamp(Number(noteEditor.fontSize) || 16, 10, 64)
 654→            });
 655→        }
 656→    }, [activeTool, createWallItem, noteDraftText, noteEditor.bgColor, noteEditor.fontColor, noteEditor.fontFamily, noteEditor.fontSize, noteEditor.fontStyle, selectedStamp, selectedStickerId, stageHeight, stageWidth]);
 657→
 658→    const handleStagePointerDown = (event) => {
