 666→                return;
 667→            }
 668→
 669→            const normalizedPointer = getNormalizedPointerPosition(stage);
 670→            if(!normalizedPointer){
 671→                return;
 672→            }
 673→
 674→            setSelectedItemId(null);
 675→            const initialPoints = [normalizedPointer.x, normalizedPointer.y];
 676→            draftDoodleRef.current = initialPoints;
 677→            setDraftDoodlePoints(initialPoints);
 678→            setIsDrawing(true);
 679→            if(event?.evt?.cancelable){
 680→                event.evt.preventDefault();
 681→            }
 682→            return;
 683→        }
 684→
 685→        if(activeTool === "stamp"){
 686→            if(!ensureCanWrite()){
 687→                return;
 688→            }
 689→
 690→            setSelectedItemId(null);
 691→            handlePlaceItem(stage);
 692→            if(event?.evt?.cancelable){
 693→                event.evt.preventDefault();
 694→            }
 695→            return;
