 708→            return;
 709→        }
 710→
 711→        const stage = event.target.getStage();
 712→        const normalizedPointer = getNormalizedPointerPosition(stage);
 713→        if(!normalizedPointer){
 714→            return;
 715→        }
 716→
 717→        const nextPoints = [...draftDoodleRef.current, normalizedPointer.x, normalizedPointer.y];
 718→        draftDoodleRef.current = nextPoints;
 719→        setDraftDoodlePoints(nextPoints);
 720→        if(event?.evt?.cancelable){
 721→            event.evt.preventDefault();
 722→        }
 723→    };
 724→
 725→    const handleStagePointerUp = () => {
 726→        if(activeTool !== "doodle"){
 727→            return;
 728→        }
 729→
 730→        const points = draftDoodleRef.current
 731→            .map((point) => Number(point))
