    padding: 0.34rem 0.45rem;
    color: var(--text-secondary);
    font-size: 0.72rem;
    min-width: 150px;
}

.fw-label{
    color: var(--text-faint);
    font-size: 0.68rem;
    text-transform: uppercase;
    letter-spacing: 0.04rem;
    font-weight: 700;
}

.fw-stamp-grid{
    display: flex;
    gap: 0.4rem;
}

.fw-stamp-btn{
