  4→const DEFAULT_ITEMS_LIMIT = 200;
  5→const MAX_ITEMS_LIMIT = 400;
  6→const NOTE_FONT_STYLES = ["normal", "bold", "italic"];
  7→const NOTE_FONT_FAMILIES = [
  8→    "Georgia",
  9→    "Courier New",
 10→    "Trebuchet MS",
 11→    "Arial",
 12→    "Times New Roman"
 13→];
 14→
 15→const clamp = (value, min, max) => Math.min(Math.max(value, min), max);
 16→
 17→const parseLimit = (limit) => {
 18→    const parsedLimit = Number(limit ?? DEFAULT_ITEMS_LIMIT);
 19→    if(Number.isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > MAX_ITEMS_LIMIT){
 20→        throw {status: 400, error: `limit should be an integer between 1 and ${MAX_ITEMS_LIMIT}`};
 21→    }
 22→    return Math.floor(parsedLimit);
 23→};
 24→
 25→const parseTypeFilters = (types) => {
 26→    if(!types){
 27→        return [];
 28→    }
 29→
 30→    const parsedTypes = String(types)
 31→        .split(",")
 32→        .map((value) => value.trim().toLowerCase())
 33→        .filter(Boolean);
 34→
 35→    const uniqueTypes = [...new Set(parsedTypes)].filter((type) => FREEDOM_WALL_ITEM_TYPES.includes(type));
 36→    return uniqueTypes;
 37→};
 38→
 39→const parseColor = (value, fallback) => {
 40→    if(typeof value !== "string"){
 41→        return fallback;
 42→    }
 43→
 44→    const trimmed = value.trim();
 45→    if(!trimmed){
 46→        return fallback;
 47→    }
 48→
 49→    return trimmed;
 50→};
 51→
 52→const normalizeNumber = (value, fallback) => {
 53→    const parsedValue = Number(value);
 54→    if(Number.isNaN(parsedValue)){
 55→        return fallback;
 56→    }
 57→    return parsedValue;
 58→};
 59→
 60→const normalizePosition = (value, fallback) => clamp(normalizeNumber(value, fallback), 0, 1);
 61→
 62→const sanitizeDoodlePayload = (payload) => {
 63→    const points = Array.isArray(payload?.points)
 64→        ? payload.points
 65→            .map((point) => Number(point))
 66→            .filter((point) => !Number.isNaN(point))
 67→            .map((point) => clamp(point, 0, 1))
 68→        : [];
 69→
 70→    if(points.length < 4){
 71→        throw {status: 400, error: "doodle payload points must contain at least 2 coordinate pairs"};
 72→    }
 73→
 74→    const sanitizedPoints = points.length % 2 === 0
 75→        ? points
 76→        : points.slice(0, -1);
 77→
 78→    const normalizedSize = clamp(normalizeNumber(payload?.size, 2.8), 1, 24);
 79→    return {
 80→        points: sanitizedPoints,
 81→        color: parseColor(payload?.color, "#5f92ff"),
 82→        size: normalizedSize,
 83→        // Backward compatibility for older DB check constraints that still expect strokeWidth.
 84→        strokeWidth: normalizedSize
 85→    };
 86→};
 87→
 88→const sanitizeStickerPayload = (payload) => {
 89→    const sticker = typeof payload?.sticker === "string" ? payload.sticker.trim() : "";
 90→    const stickerId = typeof payload?.stickerId === "string" ? payload.stickerId.trim() : "";
 91→    if(!sticker && !stickerId){
 92→        throw {status: 400, error: "sticker payload requires sticker or stickerId"};
 93→    }
 94→
 95→    const result = {
 96→        x: normalizePosition(payload?.x, 0.5),
 97→        y: normalizePosition(payload?.y, 0.5),
 98→        scale: clamp(normalizeNumber(payload?.scale, 1), 0.25, 6),
 99→        rotation: clamp(normalizeNumber(payload?.rotation, 0), -360, 360)
100→    };
101→
102→    if(sticker){
103→        result.sticker = sticker;
104→    } else {
105→        result.stickerId = stickerId;
106→    }
107→
108→    return result;
109→};
110→
111→const sanitizeStampPayload = (payload) => {
112→    const stamp = typeof payload?.stamp === "string" ? payload.stamp.trim() : "";
113→    if(!stamp){
114→        throw {status: 400, error: "stamp payload requires stamp"};
115→    }
116→
117→    return {
118→        stamp: stamp,
119→        x: normalizePosition(payload?.x, 0.5),
120→        y: normalizePosition(payload?.y, 0.5),
121→        scale: clamp(normalizeNumber(payload?.scale, 1), 0.35, 5),
122→        rotation: clamp(normalizeNumber(payload?.rotation, 0), -360, 360)
123→    };
124→};
125→
126→const sanitizeNotePayload = (payload) => {
127→    const text = typeof payload?.text === "string" ? payload.text.trim() : "";
128→    if(!text){
129→        throw {status: 400, error: "note payload requires text"};
130→    }
131→
132→    const requestedFontFamily = typeof payload?.fontFamily === "string" ? payload.fontFamily.trim() : "";
133→    const requestedFontStyle = typeof payload?.fontStyle === "string" ? payload.fontStyle.trim().toLowerCase() : "";
134→
135→    return {
