  56→    return String(a?.id || "").localeCompare(String(b?.id || ""));
  57→});
  58→
  59→const upsertById = (items = [], nextItem) => {
  60→    const existingIndex = items.findIndex((item) => String(item?.id) === String(nextItem?.id));
  61→    if(existingIndex === -1){
  62→        return [...items, nextItem];
  63→    }
  64→
  65→    const nextItems = [...items];
  66→    const previousItem = nextItems[existingIndex];
  67→    nextItems[existingIndex] = {
  68→        ...previousItem,
  69→        ...nextItem,
  70→        payload: {
  71→            ...(previousItem?.payload || {}),
  72→            ...(nextItem?.payload || {})
  73→        },
  74→        users: nextItem?.users || previousItem?.users || null
  75→    };
  76→    return nextItems;
  77→};
  78→
  79→const removeById = (items = [], itemId) => items.filter((item) => String(item?.id) !== String(itemId));
  80→
  81→const emojiCanvasCache = new Map();
  82→
  83→const useEmojiImage = (emoji, resolution = 128) => {
  84→    const [image, setImage] = useState(() => emojiCanvasCache.get(`${emoji}-${resolution}`) || null);
  85→
  86→    useEffect(() => {
  87→        if(!emoji){
  88→            setImage(null);
  89→            return;
  90→        }
  91→
  92→        const cacheKey = `${emoji}-${resolution}`;
  93→        const cached = emojiCanvasCache.get(cacheKey);
  94→        if(cached){
  95→            setImage(cached);
  96→            return;
  97→        }
  98→
  99→        const canvas = document.createElement("canvas");
 100→        canvas.width = resolution;
 101→        canvas.height = resolution;
 102→        const ctx = canvas.getContext("2d");
 103→        ctx.clearRect(0, 0, resolution, resolution);
 104→        ctx.textAlign = "center";
 105→        ctx.textBaseline = "middle";
 106→        ctx.font = `${Math.round(resolution * 0.78)}px "Segoe UI Emoji", "Apple Color Emoji", "Noto Color Emoji", sans-serif`;
 107→        ctx.fillText(emoji, resolution / 2, resolution / 2);
 108→
 109→        const img = new window.Image();
 110→        img.onload = () => {
 111→            emojiCanvasCache.set(cacheKey, img);
 112→            setImage(img);
 113→        };
 114→        img.src = canvas.toDataURL();
 115→    }, [emoji, resolution]);
 116→
 117→    return image;
 118→};
